const payload = $json.body ?? $json;
const headers = $json.headers ?? {};

const expectedSecret = 'REEMPLAZAR_CON_SECRETO_LITO';
const receivedSecret = headers['x-lito-secret'] || headers['X-Lito-Secret'] || '';

if (expectedSecret && receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized webhook request');
}

const message = (payload.message || '').trim();
if (!message) {
  throw new Error('Missing message');
}

const sessionId = payload.sessionId || `lito-${Date.now()}`;
const pagePath = payload.pagePath || '/';
const receivedAt = payload.receivedAt || new Date().toISOString();
const localReceivedAt = new Date(receivedAt).toLocaleString('es-AR', {
  timeZone: 'America/Argentina/Buenos_Aires',
  dateStyle: 'short',
  timeStyle: 'short',
});

const telegramText = [
  'Lito recibio un mensaje nuevo desde la web',
  '',
  `Sesion: ${sessionId}`,
  `Pagina: ${pagePath}`,
  `Fecha: ${localReceivedAt}`,
  '',
  'Mensaje:',
  message,
  '',
  'Responde a este mensaje para contestar en la web.',
  `Alternativa: /lito ${sessionId} tu respuesta`
].join('\n');

return [{
  json: {
    ok: true,
    sessionId,
    telegramText
  }
}];
